from spec_common import is_path_within, read_text, repo_root, summary_from_markdown


def die(message: str) -> int:
    print(message, file=sys.stderr)
    return 1


def summarize_spec(root: Path, spec_path: Path) -> str:
    try:
        return summary_from_markdown(spec_path)
    except OSError:
        return ''


def mode_rank(mode: str) -> int:
    if mode == 'full':
        return 2
    return 1


def record_identity_key(item: dict) -> tuple[str, str]:
    return (item.get('path', ''), item.get('phase', ''))


def merge_record(existing: dict, incoming: dict, replace_existing: bool = False) -> dict:
    if replace_existing:
        merged = dict(incoming)
        merged['createdAt'] = existing.get('createdAt', incoming.get('createdAt'))
        merged['updatedAt'] = now_iso()
        return merged

    merged = dict(existing)

    if mode_rank(incoming.get('mode', 'summary')) >= mode_rank(existing.get('mode', 'summary')):
        merged['mode'] = incoming.get('mode', existing.get('mode', 'summary'))

    if incoming.get('reason'):
        merged['reason'] = incoming['reason']

    if incoming.get('selectedBy'):
        merged['selectedBy'] = incoming['selectedBy']

    merged['type'] = incoming.get('type', existing.get('type', 'spec'))
    merged['path'] = incoming.get('path', existing.get('path', ''))
    merged['phase'] = incoming.get('phase', existing.get('phase', ''))
    merged['updatedAt'] = now_iso()
    merged.setdefault('createdAt', existing.get('createdAt', now_iso()))
    return merged


def upsert_jsonl(path: Path, item: dict, replace_existing: bool = False) -> tuple[str, dict]:
    rows = load_jsonl(path)
    target_key = record_identity_key(item)

    for index, existing in enumerate(rows):
        if record_identity_key(existing) == target_key:
            merged = merge_record(existing, item, replace_existing=replace_existing)
            rows[index] = merged
            write_jsonl(path, rows)
            return ('updated', merged)

    rows.append(item)
    write_jsonl(path, rows)
    return ('added', item)


def record_sort_key(item: dict) -> tuple[int, int, str, str]:
    source_rank = 0 if item.get('source') in {'implement', 'review'} else 1
    mode_rank_value = -mode_rank(item.get('mode', 'summary'))
    updated_at = item.get('updatedAt', item.get('createdAt', ''))
    path_value = item.get('path', '')
    return (source_rank, mode_rank_value, updated_at, path_value)


def normalize_records(plan_records: list[dict], phase_records: list[dict], phase: str) -> list[dict]:
    merged: dict[str, dict] = {}

    for item in plan_records:
        candidate = dict(item)
        candidate['source'] = 'plan'
        path = candidate.get('path', '')
        if path:
            merged[path] = candidate

    for item in phase_records:
        candidate = dict(item)
        candidate['source'] = phase
        path = candidate.get('path', '')
        if not path:
            continue

        if path not in merged:
            merged[path] = candidate
            continue

        existing = merged[path]
        merged[path] = merge_record(existing, candidate, replace_existing=False)
        merged[path]['source'] = phase

    rows = list(merged.values())
    rows.sort(key=record_sort_key)
    return rows


def apply_render_budget(root: Path, records: list[dict], max_full: int | None, max_chars: int | None) -> tuple[list[dict], dict]:
    used_full = 0
    used_chars = 0
    downgraded: list[str] = []
    output: list[dict] = []

    for item in records:
        row = dict(item)
        rel = row.get('path', '')
        mode = row.get('mode', 'summary')
        target = (root / rel).resolve()

        if mode == 'full' and target.is_file():
            content = read_text(target)
            content_len = len(content)

            if max_full is not None and used_full >= max_full:
                row['mode'] = 'summary'
                downgraded.append(rel)
            elif max_chars is not None and used_chars + content_len > max_chars:
                row['mode'] = 'summary'
                downgraded.append(rel)
            else:
                used_full += 1
                used_chars += content_len

        output.append(row)

    budget = {
        'maxFull': max_full,
        'usedFull': used_full,
        'maxChars': max_chars,
        'usedChars': used_chars,
        'downgraded': downgraded,
    }
    return output, budget


def render_records(root: Path, records: list[dict], title: str) -> str:
    lines = [f'## {title}', '']
    for item in records:
        rel = item.get('path', '')
        reason = item.get('reason', '')
        mode = item.get('mode', 'summary')
        source = item.get('source', '')
        spec_path = (root / rel).resolve()
        lines.append(f'- `{rel}`')
        if source:
            lines.append(f'  - Source: {source}')
        if reason:
            lines.append(f'  - Reason: {reason}')
        lines.append(f'  - Mode: {mode}')
        if mode == 'full' and spec_path.is_file():
            lines.append('  - Content:')
            lines.append('')
            for raw in read_text(spec_path).splitlines():
                lines.append(f'    {raw}')
        else:
            summary = summarize_spec(root, spec_path)
            if summary:
                lines.append(f'  - Summary: {summary}')
        lines.append('')
    if len(lines) == 2:
        lines.append('- No records selected yet')
        lines.append('')
    return '\n'.join(lines).rstrip() + '\n'


def render_records_json(root: Path, records: list[dict], budget: dict, plan_path: Path, context_dir: Path, phase: str) -> dict:
    payload_records = []

    for item in records:
        rel = item.get('path', '')
        spec_path = (root / rel).resolve()
        mode = item.get('mode', 'summary')

        payload = {
            'path': rel,
            'source': item.get('source'),
            'mode': mode,
            'reason': item.get('reason', ''),
        }

        if mode == 'full' and spec_path.is_file():
            payload['content'] = read_text(spec_path)
        else:
            summary = summarize_spec(root, spec_path)
            if summary:
                payload['summary'] = summary

        payload_records.append(payload)

    return {
        'plan': rel_posix(root, plan_path),
        'contextDir': rel_posix(root, context_dir),
        'phase': phase,
        'records': payload_records,
        'budget': budget,
    }


def cmd_init(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    ensure_project_root(root)
    try:
        plan_path = resolve_plan_path(root, args.plan)
        validate_plan_location(root, plan_path)
    except ValueError as exc:
        return die(str(exc))

    if not plan_path.is_file():
        return die(f'Plan file not found: {rel_posix(root, plan_path)}')

    context_dir = context_dir_for_plan(plan_path)
    context_dir.mkdir(parents=True, exist_ok=True)
    initialize_jsonl_files(context_dir)

    existing = load_state(context_dir) or {}
    timestamp = now_iso()
    state = {
        'schemaVersion': SCHEMA_VERSION,
        'planPath': rel_posix(root, plan_path),
        'contextDir': rel_posix(root, context_dir),
        'currentPhase': existing.get('currentPhase', 'plan'),
        'createdAt': existing.get('createdAt', timestamp),
        'updatedAt': timestamp,
        'selectionPolicy': 'planning-selected',
        'specRoot': DEFAULT_SPEC_ROOT.as_posix(),
    }
    save_state(context_dir, state)

    if args.set_current:
        set_current_plan(root, plan_path)

    print(f'Initialized context sidecar: {rel_posix(root, context_dir)}')
    if args.set_current:
        print(f'Set current plan: {rel_posix(root, plan_path)}')
    return 0


def cmd_current(args: argparse.Namespace) -> int:
    del args
    root = repo_root(Path.cwd())
    pointer = current_plan_file(root)
    plan_path = get_current_plan(root)
    if plan_path is None:
        if pointer.is_file():
            return die('Current plan pointer exists but does not resolve to a valid plan')
        print('No current plan set')
        return 0
    context_dir = context_dir_for_plan(plan_path)
    print(f'Current plan: {rel_posix(root, plan_path)}')
    print(f'Context sidecar: {rel_posix(root, context_dir)}')
    state = load_state(context_dir)
    if state:
        print(f"Current phase: {state.get('currentPhase', 'unknown')}")
    else:
        print('Current phase: unknown (state.json missing)')
    return 0


def cmd_set_current(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    try:
        plan_path = resolve_plan_path(root, args.plan)
        validate_plan_location(root, plan_path)
    except ValueError as exc:
        return die(str(exc))
    if not plan_path.is_file():
        return die(f'Plan file not found: {rel_posix(root, plan_path)}')
    set_current_plan(root, plan_path)
    print(f'Set current plan: {rel_posix(root, plan_path)}')
    return 0


def cmd_clear_current(args: argparse.Namespace) -> int:
    del args
    root = repo_root(Path.cwd())
    path = current_plan_file(root)
    if path.exists():
        path.unlink()
    print('Cleared current plan')
    return 0


def resolve_spec_path(root: Path, value: str) -> Path:
    candidate = Path(value)
    if candidate.is_absolute():
        spec = candidate.resolve()
    else:
        spec = (root / candidate).resolve()
    spec_root = (root / DEFAULT_SPEC_ROOT).resolve()
    if not is_path_within(spec_root, spec):
        raise ValueError(f'Spec path must live under {DEFAULT_SPEC_ROOT.as_posix()}: {value}')
    if not spec.is_file():
        raise ValueError(f'Spec file not found: {value}')
    return spec


def load_plan_from_args(root: Path, plan_arg: str | None) -> Path | None:
    if plan_arg:
        plan = resolve_plan_path(root, plan_arg)
        validate_plan_location(root, plan)
        return plan
    return get_current_plan(root)


def update_phase_state(context_dir: Path, phase: str) -> None:
    state = load_state(context_dir) or {}
    timestamp = now_iso()
    state.setdefault('schemaVersion', SCHEMA_VERSION)
    state['currentPhase'] = phase
    state['updatedAt'] = timestamp
    save_state(context_dir, state)


def cmd_add(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    try:
        plan_path = load_plan_from_args(root, args.plan)
        if plan_path is None:
            return die('No current plan set; pass --plan or run set-current first')
        validate_plan_location(root, plan_path)
        spec_path = resolve_spec_path(root, args.spec)
    except ValueError as exc:
        return die(str(exc))

    context_dir = context_dir_for_plan(plan_path)
    if not context_dir.is_dir():
        return die(f'Context sidecar not initialized: {rel_posix(root, context_dir)}')

    phase_file = context_dir / PHASE_FILES[args.phase]
    timestamp = now_iso()
    record = {
        'type': 'spec',
        'path': rel_posix(root, spec_path),
        'reason': args.reason,
        'phase': args.phase,
        'mode': args.mode,
        'selectedBy': args.selected_by,
        'createdAt': timestamp,
        'updatedAt': timestamp,
    }

    if args.no_dedupe:
        append_jsonl(phase_file, record)
        action = 'added'
        saved = record
    else:
        action, saved = upsert_jsonl(phase_file, record, replace_existing=args.replace_existing)

    update_phase_state(context_dir, args.phase)

    if action == 'updated':
        print(f'Updated spec in {phase_file.name}: {saved["path"]}')
    else:
        print(f'Added spec to {phase_file.name}: {saved["path"]}')
    print(f'Reason: {saved.get("reason", "")}')
    print(f'Mode: {saved.get("mode", "summary")}')
    return 0


def cmd_render(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    try:
        plan_path = load_plan_from_args(root, args.plan)
        if plan_path is None:
            return die('No current plan set; pass --plan or run set-current first')
        validate_plan_location(root, plan_path)
    except ValueError as exc:
        return die(str(exc))

    context_dir = context_dir_for_plan(plan_path)
    if not context_dir.is_dir():
        return die(f'Context sidecar not initialized: {rel_posix(root, context_dir)}')

    state = load_state(context_dir) or {}
    plan_records = load_jsonl(context_dir / PHASE_FILES['plan'])
    phase_records = load_jsonl(context_dir / PHASE_FILES[args.phase])

    if args.no_dedupe:
        normalized = []
        for item in plan_records:
            row = dict(item)
            row['source'] = 'plan'
            normalized.append(row)
        if args.phase != 'plan':
            for item in phase_records:
                row = dict(item)
                row['source'] = args.phase
                normalized.append(row)
    else:
        normalized = normalize_records(plan_records, phase_records, args.phase)

    budgeted, budget = apply_render_budget(
        root,
        normalized,
        max_full=args.max_full,
        max_chars=args.max_chars,
    )

    if args.json:
        payload = render_records_json(
            root=root,
            records=budgeted,
            budget=budget,
            plan_path=plan_path,
            context_dir=context_dir,
            phase=args.phase,
        )
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return 0

    sections = [
        '## Current Plan',
        '',
        f'- Plan: `{rel_posix(root, plan_path)}`',
        f'- Context sidecar: `{rel_posix(root, context_dir)}`',
        f"- Current phase: {state.get('currentPhase', 'unknown')}",
        f'- Render phase: {args.phase}',
        '',
        render_records(root, budgeted, 'Selected Context').rstrip(),
    ]

    if budget.get('downgraded'):
        sections.extend([
            '',
            '## Budget Notes',
            '',
            f"- Downgraded to summary: {', '.join(f'`{item}`' for item in budget['downgraded'])}",
        ])

    print('\n'.join(sections).rstrip())
    return 0


def verify_jsonl_records(root: Path, context_dir: Path, filename: str) -> list[str]:
    path = context_dir / filename
    problems: list[str] = []
    try:
        rows = load_jsonl(path)
    except ValueError as exc:
        return [str(exc)]
    for item in rows:
        rel = item.get('path')
        if not isinstance(rel, str) or not rel:
            problems.append(f'{filename}: missing path field')
            continue
        target = (root / rel).resolve()
        if not is_path_within(root.resolve(), target):
            problems.append(f'{filename}: path escapes repo root: {rel}')
            continue
        if not target.is_file():
            problems.append(f'{filename}: referenced file missing: {rel}')
    return problems


def cmd_verify(args: argparse.Namespace) -> int:
    root = repo_root(Path.cwd())
    try:
        if args.current:
            plan_path = get_current_plan(root)
            if plan_path is None:
                return die('No current plan set')
        else:
            plan_path = resolve_plan_path(root, args.plan)
        validate_plan_location(root, plan_path)
    except ValueError as exc:
        return die(str(exc))

    if not plan_path.is_file():
        return die(f'Plan file not found: {rel_posix(root, plan_path)}')

    context_dir = context_dir_for_plan(plan_path)
    if not context_dir.is_dir():
        return die(f'Context sidecar not initialized: {rel_posix(root, context_dir)}')

    state_path = context_dir / 'state.json'
    if not state_path.is_file():
        return die(f'Missing state.json: {rel_posix(root, state_path)}')
    try:
        state = json.loads(state_path.read_text(encoding='utf-8'))
    except json.JSONDecodeError as exc:
        return die(f'Invalid state.json: {exc.msg}')

    problems: list[str] = []
    if state.get('planPath') != rel_posix(root, plan_path):
        problems.append('state.json planPath does not match target plan')
    if state.get('contextDir') != rel_posix(root, context_dir):
        problems.append('state.json contextDir does not match sidecar directory')

    for filename in PHASE_FILES.values():
        file_path = context_dir / filename
        if not file_path.is_file():
            problems.append(f'Missing {filename}')
        else:
            problems.extend(verify_jsonl_records(root, context_dir, filename))

    current = get_current_plan(root)
    if args.current and current is not None and current.resolve() != plan_path.resolve():
        problems.append('current-plan does not resolve to the verified plan')

    if problems:
        for problem in problems:
            print(f'- {problem}')
        return 1

    print(f'Plan context OK: {rel_posix(root, plan_path)}')
    print(f'Context sidecar OK: {rel_posix(root, context_dir)}')
    return 0


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser()
    subparsers = parser.add_subparsers(dest='command', required=True)

    init_parser = subparsers.add_parser('init')
    init_parser.add_argument('plan')
    init_parser.add_argument('--set-current', action='store_true')
    init_parser.set_defaults(func=cmd_init)

    current_parser = subparsers.add_parser('current')
    current_parser.set_defaults(func=cmd_current)

    set_current_parser = subparsers.add_parser('set-current')
    set_current_parser.add_argument('plan')
    set_current_parser.set_defaults(func=cmd_set_current)

    clear_current_parser = subparsers.add_parser('clear-current')
    clear_current_parser.set_defaults(func=cmd_clear_current)

    add_parser = subparsers.add_parser('add')
    add_parser.add_argument('--phase', choices=sorted(PHASE_FILES), required=True)
    add_parser.add_argument('--plan')
    add_parser.add_argument('--spec', required=True)
    add_parser.add_argument('--reason', required=True)
    add_parser.add_argument('--mode', choices=('summary', 'full'), default='summary')
    add_parser.add_argument('--selected-by', default='planning')
    add_parser.add_argument('--no-dedupe', action='store_true')
    add_parser.add_argument('--replace-existing', action='store_true')
    add_parser.set_defaults(func=cmd_add)

    render_parser = subparsers.add_parser('render')
    render_parser.add_argument('--phase', choices=('plan', 'implement', 'review'), required=True)
    render_parser.add_argument('--plan')
    render_parser.add_argument('--max-full', type=int)
    render_parser.add_argument('--max-chars', type=int)
    render_parser.add_argument('--json', action='store_true')
    render_parser.add_argument('--no-dedupe', action='store_true')
    render_parser.set_defaults(func=cmd_render)

    verify_parser = subparsers.add_parser('verify')
    group = verify_parser.add_mutually_exclusive_group(required=True)
    group.add_argument('--current', action='store_true')
    group.add_argument('plan', nargs='?')
    verify_parser.set_defaults(func=cmd_verify)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return args.func(args)


if __name__ == '__main__':
    raise SystemExit(main())
